-- ============================================
-- Legislacao full-site: wellington-fagundes / Senado / projetos_lei
-- Seed completo do recorte: autoria parlamentar substantiva Senado 2015-2026
-- ============================================
-- Fonte oficial: Senado Federal Dados Abertos
--   https://legis.senado.leg.br/dadosabertos/senador/1173/autorias.json
--   https://legis.senado.leg.br/dadosabertos/materia/{codigo}.json
--   https://legis.senado.leg.br/dadosabertos/materia/autoria/{codigo}.json
--   https://www25.senado.leg.br/web/atividade/materias/-/materia/{codigo}
--
-- Artefato de auditoria:
--   fonte interna de curadoria
--
-- Coverage:
--   coverage_id    = wellington-fagundes-senado-completo-autoria-substantiva-2015-2026-20260506
--   coverage_scope = inventario_completo_senado_autoria_substantiva_2015_2026_20260506
--
-- Filtro factual: endpoint senador/1173/autorias.json com
--   IndicadorAutorPrincipal=Sim, siglas substantivas em
--   (PLS, PL, PEC, PLP, PRS, PDL, PDS, PCE), e endpoint
--   materia/autoria/{codigo}.json confirmando CodigoParlamentar=1173
--   com NumOrdemAutor=1. Resultado deste snapshot: 125 rows.
--
-- O recorte e completo apenas para a autoria parlamentar substantiva no Senado
-- retornada pelo endpoint oficial. Nao e inventario completo da vida publica do
-- candidato.
--
-- Esta migration NAO escreve em legislacao_mandato_executivo.
-- Esta migration NAO escreve em historico_politico.
-- Esta migration insere rows ausentes e atualiza coverage/metadata somente em
-- rows alvo Senado sem coverage_id divergente.
-- Esta migration NAO popula tema, destaque, destaque_motivo nem situacao
--   (campos editoriais/curatoriais, fora do contrato bruto de ingest oficial).
-- Esta migration NAO promove UI/whitelist publica; isso exige novo fechamento.
-- ============================================

DO $$
DECLARE
  cand_id uuid;
  projetos_total int;
  target_present int;
  target_count int;
  target_with_other_coverage int;
  mandato_senado_count int;
BEGIN
  SELECT id INTO cand_id FROM candidatos WHERE slug = 'wellington-fagundes';

  IF cand_id IS NULL THEN
    RAISE NOTICE 'wellington-fagundes: candidato ausente neste banco local/CI minimo; seed projetos_lei Senado pulado';
    RETURN;
  END IF;

  SELECT count(*) INTO projetos_total
  FROM projetos_lei
  WHERE candidato_id = cand_id;

  SELECT count(*) INTO target_count
  FROM projetos_lei
  WHERE candidato_id = cand_id
    AND coverage_id = 'wellington-fagundes-senado-completo-autoria-substantiva-2015-2026-20260506';

  SELECT count(*) INTO target_present
  FROM projetos_lei
  WHERE candidato_id = cand_id
    AND proposicao_id_api IN ('119624', '120462', '121320', '121883', '122549', '123499', '123558', '123984', '123985', '124338', '120542', '124792', '125009', '125065', '125687', '126442', '126667', '126976', '127048', '127694', '133385', '133538', '140135', '140144', '136767', '136316', '136319', '136839', '137057', '137343', '137341', '137827', '139055', '139326', '139412', '139839', '140140', '139069', '140735', '142021', '142072', '140484', '140742', '140736', '141303', '141348', '141831', '142507', '143254', '143302', '143572', '143584', '145403', '145414', '145842', '145843', '141470', '142075', '145444', '143034', '146407', '146699', '146700', '147196', '147209', '147263', '147443', '147929', '148044', '148226', '148564', '148839', '148885', '148936', '149293', '149944', '150353', '150354', '150355', '150703', '150831', '150947', '151162', '147779', '148795', '152928', '152090', '154786', '153381', '153665', '154745', '154987', '155091', '155123', '156581', '158402', '158586', '161143', '156961', '163264', '162406', '163291', '163696', '163766', '164098', '164112', '161900', '166202', '169121', '171885', '168631', '167604', '167767', '168049', '168264', '168738', '170059', '170219', '170441', '170464', '171878', '171932', '173300', '172746', '173261');

  SELECT count(*) INTO target_with_other_coverage
  FROM projetos_lei
  WHERE candidato_id = cand_id
    AND proposicao_id_api IN ('119624', '120462', '121320', '121883', '122549', '123499', '123558', '123984', '123985', '124338', '120542', '124792', '125009', '125065', '125687', '126442', '126667', '126976', '127048', '127694', '133385', '133538', '140135', '140144', '136767', '136316', '136319', '136839', '137057', '137343', '137341', '137827', '139055', '139326', '139412', '139839', '140140', '139069', '140735', '142021', '142072', '140484', '140742', '140736', '141303', '141348', '141831', '142507', '143254', '143302', '143572', '143584', '145403', '145414', '145842', '145843', '141470', '142075', '145444', '143034', '146407', '146699', '146700', '147196', '147209', '147263', '147443', '147929', '148044', '148226', '148564', '148839', '148885', '148936', '149293', '149944', '150353', '150354', '150355', '150703', '150831', '150947', '151162', '147779', '148795', '152928', '152090', '154786', '153381', '153665', '154745', '154987', '155091', '155123', '156581', '158402', '158586', '161143', '156961', '163264', '162406', '163291', '163696', '163766', '164098', '164112', '161900', '166202', '169121', '171885', '168631', '167604', '167767', '168049', '168264', '168738', '170059', '170219', '170441', '170464', '171878', '171932', '173300', '172746', '173261')
    AND coverage_id IS NOT NULL
    AND coverage_id <> 'wellington-fagundes-senado-completo-autoria-substantiva-2015-2026-20260506';

  IF target_with_other_coverage <> 0 THEN
    RAISE EXCEPTION 'Pre-condicao wellington-fagundes: % rows alvo Senado ja tem coverage_id divergente', target_with_other_coverage;
  END IF;

  SELECT count(*) INTO mandato_senado_count
  FROM historico_politico hp
  WHERE hp.candidato_id = cand_id
    AND COALESCE(hp.tipo_evento, 'mandato') = 'mandato'
    AND (hp.cargo ILIKE '%Senador%' OR hp.cargo_canonico = 'Senador')
    AND UPPER(COALESCE(hp.estado, '')) = 'MT'
    AND COALESCE(hp.periodo_inicio, 9999) <= 2026
    AND COALESCE(hp.periodo_fim, 9999) >= 2015;

  IF mandato_senado_count < 1 THEN
    RAISE EXCEPTION 'Pre-condicao wellington-fagundes: mandato Senado/MT 2015-2026 nao encontrado em historico_politico';
  END IF;
END $$;

