    ('PL', '4147', 2021, 'Incentiva programas nacionais de atendimento ao homem, em caráter preventivo à violência contra as mulheres, para fins de equânime desenvolvimento humano, regional e social, nos termos da Convenção sobre a Eliminação de todas as Formas de Discriminação contra a Mulher - ONU e da Convenção Interamericana para Prevenir, Punir e Erradicar a Violência contra a Mulher, de Belém do Pará – OEA. De igual forma, instrumentaliza mecanismos em canais de assistência preventiva para fins de contenção à violência doméstica e familiar, nos termos do art. 226, §8°, da Constituição Federal, bem como arts. 1°, 8°, VIII, 35, IV da Lei 11.340/06.', 'Senado', '150947', 'https://www25.senado.leg.br/web/atividade/materias/-/materia/150947', 'wellington-fagundes-senado-completo-autoria-substantiva-2015-2026-20260506', 'inventario_completo_senado_autoria_substantiva_2015_2026_20260506', '{"proposicao_id_api":"150947","descricao_identificacao":"PL 4147/2021","data_apresentacao":"2021-11-24","casa":"SF","codigo_parlamentar_senado":1173,"indicador_autor_principal_endpoint_senador":"Sim","indicador_outros_autores_endpoint_senador":"Não","num_ordem_autor":1,"total_autores":1,"partido_autor_no_protocolo":"PL","uf_autor_no_protocolo":"MT","autor_nome":"Wellington Fagundes","fonte":"Senado Federal Dados Abertos","autorias_endpoint":"https://legis.senado.leg.br/dadosabertos/senador/1173/autorias.json","autoria_endpoint":"https://legis.senado.leg.br/dadosabertos/materia/autoria/150947.json","detalhe_endpoint":"https://legis.senado.leg.br/dadosabertos/materia/150947.json","public_url":"https://www25.senado.leg.br/web/atividade/materias/-/materia/150947","coverage_id":"wellington-fagundes-senado-completo-autoria-substantiva-2015-2026-20260506","coverage_scope":"inventario_completo_senado_autoria_substantiva_2015_2026_20260506","lote":"A","tabela_alvo":"projetos_lei","legislacao_mandato_executivo_mixed":false,"curation_batch_id":"wellington-fagundes-senado-lote-a-20260506","sna