DO $$
DECLARE
  cand_id uuid;
  uncovered_year_count int;
BEGIN
  SELECT id INTO cand_id FROM candidatos WHERE slug = 'wellington-fagundes';

  IF cand_id IS NULL THEN
    RAISE NOTICE 'wellington-fagundes: validacao de mandato Senado pulada porque candidato nao existe neste banco local/CI minimo';
    RETURN;
  END IF;

  SELECT count(DISTINCT seed.ano) INTO uncovered_year_count
  FROM _seed_wellington_fagundes_senado_lote_a_projetos seed
  WHERE NOT EXISTS (
    SELECT 1
    FROM historico_politico hp
    WHERE hp.candidato_id = cand_id
      AND COALESCE(hp.tipo_evento, 'mandato') = 'mandato'
      AND (hp.cargo ILIKE '%Senador%' OR hp.cargo_canonico = 'Senador')
      AND UPPER(COALESCE(hp.estado, '')) = 'MT'
      AND COALESCE(hp.periodo_inicio, 9999) <= seed.ano
      AND COALESCE(hp.periodo_fim, 9999) >= seed.ano
  );

  IF uncovered_year_count <> 0 THEN
    RAISE EXCEPTION 'Pre-condicao wellington-fagundes: existem % anos de proposicoes Senado sem cobertura em mandato Senado/MT', uncovered_year_count;
  END IF;
END $$;

WITH target AS (
  SELECT c.id AS candidato_id
  FROM candidatos c
  WHERE c.slug = 'wellington-fagundes'
)
INSERT INTO projetos_lei (
  candidato_id,
  tipo,
  numero,
  ano,
  ementa,
  fonte,
  proposicao_id_api,
  url_inteiro_teor,
  coverage_id,
  coverage_scope,
  metadata
)
SELECT
  target.candidato_id,
  seed.tipo,
  seed.numero,
  seed.ano,
  seed.ementa,
  seed.fonte,
  seed.proposicao_id_api,
  seed.url_inteiro_teor,
  seed.coverage_id,
  seed.coverage_scope,
  seed.metadata
FROM target
CROSS JOIN _seed_wellington_fagundes_senado_lote_a_projetos AS seed
ON CONFLICT (candidato_id, proposicao_id_api) DO UPDATE SET
  tipo = EXCLUDED.tipo,
  numero = EXCLUDED.numero,
  ano = EXCLUDED.ano,
  ementa = EXCLUDED.ementa,
  fonte = EXCLUDED.fonte,
  url_inteiro_teor = EXCLUDED.url_inteiro_teor,
  coverage_id = EXCLUDED.coverage_id,
  coverage_scope = EXCLUDED.coverage_scope,
  metadata = COALESCE(projetos_lei.metadata, '{}'::jsonb) || EXCLUDED.metadata
WHERE projetos_lei.coverage_id IS NULL
   OR projetos_lei.coverage_id = EXCLUDED.coverage_id;

DO $$
DECLARE
  cand_id uuid;
  total_count int;
  target_count int;
  scope_count int;
  lme_count int;
BEGIN
  SELECT id INTO cand_id FROM candidatos WHERE slug = 'wellington-fagundes';

  IF cand_id IS NULL THEN
    RAISE NOTICE 'wellington-fagundes: pos-condicao pulada porque candidato nao existe neste banco local/CI minimo';
    RETURN;
  END IF;

  SELECT count(*) INTO total_count
  FROM projetos_lei
  WHERE candidato_id = cand_id;

  SELECT count(*) INTO target_count
  FROM projetos_lei
  WHERE candidato_id = cand_id
    AND fonte = 'Senado'
    AND proposicao_id_api IN ('119624', '120462', '121320', '121883', '122549', '123499', '123558', '123984', '123985', '124338', '120542', '124792', '125009', '125065', '125687', '126442', '126667', '126976', '127048', '127694', '133385', '133538', '140135', '140144', '136767', '136316', '136319', '136839', '137057', '137343', '137341', '137827', '139055', '139326', '139412', '139839', '140140', '139069', '140735', '142021', '142072', '140484', '140742', '140736', '141303', '141348', '141831', '142507', '143254', '143302', '143572', '143584', '145403', '145414', '145842', '145843', '141470', '142075', '145444', '143034', '146407', '146699', '146700', '147196', '147209', '147263', '147443', '147929', '148044', '148226', '148564', '148839', '148885', '148936', '149293', '149944', '150353', '150354', '150355', '150703', '150831', '150947', '151162', '147779', '148795', '152928', '152090', '154786', '153381', '153665', '154745', '154987', '155091', '155123', '156581', '158402', '158586', '161143', '156961', '163264', '162406', '163291', '163696', '163766', '164098', '164112', '161900', '166202', '169121', '171885', '168631', '167604', '167767', '168049', '168264', '168738', '170059', '170219', '170441', '170464', '171878', '171932', '173300', '172746', '173261');

  SELECT count(*) INTO scope_count
  FROM projetos_lei
  WHERE candidato_id = cand_id
    AND coverage_id = 'wellington-fagundes-senado-completo-autoria-substantiva-2015-2026-20260506'
    AND coverage_scope = 'inventario_completo_senado_autoria_substantiva_2015_2026_20260506';

  SELECT count(*) INTO lme_count
  FROM legislacao_mandato_executivo
  WHERE candidato_id = cand_id;

  IF target_count <> 125 THEN
    RAISE EXCEPTION 'Pos-apply wellington-fagundes: esperadas 125 rows alvo Senado em projetos_lei, encontradas %', target_count;
  END IF;

  IF scope_count <> 125 THEN
    RAISE EXCEPTION 'Pos-apply wellington-fagundes: esperadas 125 rows com coverage_id/scope alvo, encontradas %', scope_count;
  END IF;

  IF lme_count <> 0 THEN
    RAISE EXCEPTION 'Pos-apply wellington-fagundes: legislacao_mandato_executivo deve permanecer 0, encontrado %', lme_count;
  END IF;

  RAISE NOTICE 'Pos-apply wellington-fagundes Senado Lote A: projetos_lei=% coverage_scope=% legislacao_mandato_executivo=%', total_count, scope_count, lme_count;
END $$;
